#include <iostream>#include <string>#include <vector>#include <algorithm> using namespace std; void solve() {    string s;    cin >> s;        long long current_sum = 0;    vector<int> digits;    for (char c : s) {        int d = c - '0';        current_sum += d;        digits.push_back(d);    }        if (current_sum <= 9) {        cout << 0 << endl;        return;    }     int moves = 0;            int first_digit = s[0] - '0';    vector<int> others;    for(int i = 1; i < digits.size(); ++i) {        others.push_back(digits[i]);    }    sort(others.rbegin(), others.rend());         vector<int> reductions;    reductions.push_back(max(0, first_digit - 1));     for(int d : others) {        reductions.push_back(d);     }        sort(reductions.rbegin(), reductions.rend());     for (int r : reductions) {        current_sum -= r;        moves++;        if (current_sum <= 9) {            cout << moves << endl;            return;        }    }} int main() {    int t;    cin >> t;    while (t--) {        solve();    }    return 0;}